**Efficiency:** We directly compute the needed block counts using powers of ∣D∣|D|∣D∣ and subtract counts until we pinpoint the correct length.
**Simplicity:** The approach converts the “rank” NNN into a digit-by-digit representation in a numeral system with base ∣D∣|D|∣D∣ (with a minor adjustment for the first digit if 000 is included).
Below is the complete C++ solution using the iterative construction method:

`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;string&gt;
using namespace std;

typedef long long ll;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin &gt;&gt; t;
    while (t--) {
        int d;
        ll N;
        cin &gt;&gt; d &gt;&gt; N;
        vector&lt;int&gt; digits(d);
        for (int i = 0; i &lt; d; i++){
            cin &gt;&gt; digits[i];
        }

        // If only one digit is available, the answer is that digit repeated N times.
        if (d == 1) {
            cout &lt;&lt; string(N, char(digits[0] + '0')) &lt;&lt; "\n";
            continue;
        }

        // For one-digit numbers, output directly if N &lt;= d.
        if (N &lt;= d) {
            cout &lt;&lt; char(digits[N - 1] + '0') &lt;&lt; "\n";
            continue;
        }

        bool hasZero = (digits[0] == 0);

        // Subtract one-digit numbers.
        N -= d;
        int len = 2;
        long long countL;

        // Find the digit-length where the N-th number exists.
        while (true) {
            // Calculate valid count for numbers with current length.
            countL = (hasZero ? (d - 1) : d);
            for (int i = 1; i &lt; len; i++) {
                countL *= d;
            }
            if (N &lt;= countL) break;
            N -= countL;
            len++;
        }

        // Construct the number digit by digit.
        string ans = "";
        for (int pos = 0; pos &lt; len; pos++) {
            long long blockSize = 1;
            int rem = len - pos - 1;
            for (int i = 0; i &lt; rem; i++) {
                blockSize *= d;
            }
            int startIndex = (pos == 0 &amp;&amp; hasZero) ? 1 : 0;
            for (int j = startIndex; j &lt; d; j++) {
                if (N &lt;= blockSize) {
                    ans.push_back(char(digits[j] + '0'));
                    break;
                } else {
                    N -= blockSize;
                }
            }
        }

        cout &lt;&lt; ans &lt;&lt; "\n";
    }
    return 0;
}
